Implementasi Observer Pattern yang aman dan efisien untuk sistem monitoring atau event handling. Kode ini mencakup thread-safety dasar untuk lingkungan server multithread.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import threading
import logging

# Konfigurasi Logging untuk Audit Trail
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    def __init__(self):
        self._observers: List[Observer] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        """Menambahkan observer dengan validasi duplikasi."""
        with self._lock:
            if observer not in self._observers:
                self._observers.append(observer)
                logging.info(f"Observer attached: {observer.__class__.__name__}")
            else:
                logging.warning(f"Duplicate observer detected: {observer.__class__.__name__}")

    def detach(self, observer: Observer) -> None:
        """Menghapus observer secara aman."""
        with self._lock:
            if observer in self._observers:
                self._observers.remove(observer)
                logging.info(f"Observer detached: {observer.__class__.__name__}")
            else:
                logging.warning(f"Observer not found: {observer.__class__.__name__}")

    def notify(self) -> None:
        """Memberi notifikasi ke semua observer terdaftar."""
        with self._lock:
            # Copy list untuk menghindari race condition saat iterasi
            observers = self._observers[:] 

        for observer in observers:
            try:
                observer.update(self)
            except Exception as e:
                # Isolasi error agar satu observer gagal tidak mematikan seluruh sistem
                logging.error(f"Error notifying {observer.__class__.__name__}: {str(e)}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

# Contoh Concrete Observer
class SecurityMonitor(Observer):
    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        # Validasi input state sebelum diproses
        if isinstance(state, dict) and 'event' in state:
            logging.info(f"[SECURITY] Event Detected: {state['event']}")
        else:
            logging.warning("[SECURITY] Invalid state format received")

# Usage
if __name__ == "__main__":
    subject = Subject()
    monitor = SecurityMonitor()

    subject.attach(monitor)
    subject.set_state({"event": "LOGIN_ATTEMPT", "ip": "192.168.1.1"})
    subject.detach(monitor)
```

### Catatan Teknis & Keamanan:

1.  **Thread Safety**: Menggunakan `threading.Lock` untuk mencegah race condition saat menambah/menghapus observer saat notifikasi berjalan. Kritikal untuk aplikasi web tinggi (High Concurrency).
2.  **Error Isolation**: Blok `try-except` di dalam `notify` memastikan jika satu observer crash (misal karena bug logic), observer lain tetap menerima notifikasi. Ini mencegah Denial of Service pada event system.
3.  **Input Validation**: Observer harus memvalidasi data yang diterima dari Subject (`isinstance`, cek key) untuk mencegah TypeError atau vulnerability jika data berasal dari sumber eksternal.
4.  **Logging**: Semua aksi attachment dan error dicatat untuk keperluan audit keamanan.

Gunakan pola ini untuk sistem log, alerting security, atau update status server real-time. Jangan gunakan untuk operasi blokings yang berat di dalam method `update`.
